#include<bits/stdc++.h>
using namespace std;
int n,m,L[300010],R[300010],a[300010],id[300010],p[300010];
vector<int> vec[300010];
unsigned long long sum[300010],val[300010],ans[300010],V[300010];
int lowbit(int x)
{
	return x&-x;
}
void add(int x,unsigned long long v)
{
	for(int i=x;i<=m+1;i+=lowbit(i))
	{
		sum[i]+=v;
	}
}
int query(unsigned long long x)
{
	int ans=0;
	for(int i=x;i>=1;i-=lowbit(i))
	{
		ans+=sum[i];
	}
	return ans;
}
void dfs(int l,int r,vector<int> v)
{
	if(l==r)
	{
		for(int i:v)
		{
			ans[i]=l;
		}
		return;
	}
	int mid=(l+r)>>1;
	for(int i=l;i<=mid;i++)
	{
		if(L[i]>R[i])
		{
			add(m+1,-V[i]);
			add(1,V[i]);
		}
		add(L[i],V[i]);
		add(R[i]+1,-V[i]);
	}
	vector<int> vl,vr;
	for(int i:v)
	{
		unsigned long long sum=0;
		for(int j:vec[i])
		{
			sum+=query(j);
            if(sum>=val[i])
            {
                break;
            }
		}
		if(sum>=val[i])
		{
			vl.push_back(i);
		}
		else
		{
			vr.push_back(i);
		}
	}
	dfs(mid+1,r,vr);
	for(int i=l;i<=mid;i++)
	{
		if(L[i]>R[i])
		{
			add(m+1,V[i]);
			add(1,-V[i]);
		}
		add(L[i],-V[i]);
		add(R[i]+1,V[i]);
	}
	dfs(l,mid,vl);
}
int main()
{
	scanf("%d%d",&n,&m);
	for(int i=1;i<=m;i++)
	{
		scanf("%d",&a[i]);
		vec[a[i]].push_back(i);
	}
	for(int i=1;i<=n;i++)
	{
		scanf("%llu",&val[i]);
	}
	int k;
	scanf("%d",&k);
	for(int i=1;i<=k;i++)
	{
		scanf("%d%d%llu",&L[i],&R[i],&V[i]);
	}
	vector<int> v1;
	for(int i=1;i<=n;i++)
	{
		v1.push_back(i);
	}
	L[k+1]=R[k+1]=1;
	V[k+1]=0;
	dfs(1,k+1,v1);
	for(int i=1;i<=n;i++)
	{
		if(ans[i]==k+1)
		{
			printf("NIE\n");
			continue;
		}
		printf("%d\n",ans[i]);
	}
	return 0;
}
